features.snippet:
interface AXIS_IF #(
    parameter int DATA_W = 128
) (input logic clk);
  logic [DATA_W-1:0] tdata;
endinterface

module foobar #(
    parameter int N = 2
) (
    input logic clk,
    AXIS_IF.slave s_axis[N-1:0]
);
  generate
    genvar i;
    for (i = 0; i < N; i++) begin : gen_loop
      AXIS_IF #(
          .DATA_W(s_axis[i].DATA_W)
      ) axis_internal (.clk(s_axis[i].clk));
    end
  endgenerate
endmodule
